reference_command:
geo=$(curl -s 'https://geocoding-api.open-meteo.com/v1/search?name=San+Francisco&count=1&language=en&format=json')
lat=$(echo "$geo" | jq -r '.results[0].latitude')
lon=$(echo "$geo" | jq -r '.results[0].longitude')
fc=$(curl -s "https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&daily=weather_code&timezone=auto&forecast_days=2")
code=$(echo "$fc" | jq -r '.daily.weather_code[1] // .daily.weather_code[0]')
clear=no
cloudy=no
rain=no
snowy=no
case "$code" in
  0) clear=yes ;;
  1|2|3|45|48) cloudy=yes ;;
  51|53|55|56|57|61|63|65|66|67|80|81|82|95|96|99) rain=yes ;;
  71|73|75|77|85|86) snowy=yes ;;
esac
value=no
case "rain" in
  rain) value="$rain" ;;
  cloudy) value="$cloudy" ;;
  snowy) value="$snowy" ;;
  clear) value="$clear" ;;
  *) value=no ;;
esac
printf 'rain_tomorrow: %s\n' "$value" > "$HOME/Desktop/weather_tomorrow_rain_2_1.txt"

